import math

class TranslationScorer:
    def __init__(self, threshold=0.3):
        self.threshold = threshold

    def char_trigrams(self, text):
        text = text.lower()
        if len(text) < 3:
            return {}
        tri = {}
        for i in range(len(text) - 2):
            key = text[i:i+3]
            tri[key] = tri.get(key, 0) + 1
        return tri

    def cosine_similarity(self, vec_a, vec_b):
        shared = set(vec_a) & set(vec_b)
        dot = sum(vec_a[w] * vec_b[w] for w in shared)
        mag_a = math.sqrt(sum(v**2 for v in vec_a.values()))
        mag_b = math.sqrt(sum(v**2 for v in vec_b.values()))
        if mag_a == 0 or mag_b == 0:
            return 0.0
        return dot / (mag_a * mag_b)

    def score_translation(self, source, translation):
        src_vec = self.char_trigrams(source)
        tgt_vec = self.char_trigrams(translation)
        score = self.cosine_similarity(src_vec, tgt_vec)
        return {"score": score, "status": "pass" if score >= self.threshold else "review"}

